import{_ as a,o as i,c as o,a6 as t}from"./chunks/framework.wLlb4ebq.js";const u=JSON.parse('{"title":"安全与权限","description":"","frontmatter":{},"headers":[],"relativePath":"architecture/security.md","filePath":"architecture/security.md"}'),l={name:"architecture/security.md"};function s(d,e,n,c,r,h){return i(),o("div",null,[...e[0]||(e[0]=[t(`<h1 id="安全与权限" tabindex="-1">安全与权限 <a class="header-anchor" href="#安全与权限" aria-label="Permalink to “安全与权限”">​</a></h1><p>LD-Notion 同时支持用户手动操作和 AI 触发操作。为了避免自然语言误操作直接写入工作区，写入口会经过统一守卫层。</p><h2 id="权限等级" tabindex="-1">权限等级 <a class="header-anchor" href="#权限等级" aria-label="Permalink to “权限等级”">​</a></h2><table tabindex="0"><thead><tr><th>等级</th><th>能力边界</th><th>适合场景</th></tr></thead><tbody><tr><td>只读</td><td>搜索、读取、查看详情</td><td>初次体验、只问不改</td></tr><tr><td>标准</td><td>创建页面、写内容、更新属性、自动分类</td><td>日常整理</td></tr><tr><td>高级</td><td>移动、复制、归档、数据库结构类操作</td><td>深度整理</td></tr><tr><td>管理员</td><td>高风险管理操作</td><td>确认后短期开启</td></tr></tbody></table><h2 id="operationguard" tabindex="-1">OperationGuard <a class="header-anchor" href="#operationguard" aria-label="Permalink to “OperationGuard”">​</a></h2><div class="language-mermaid"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart TD</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  Action[用户或 AI 请求操作] --&gt; Classify[识别操作类型]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  Classify --&gt; Read{只读?}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  Read --&gt;|是| AllowRead[直接执行]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  Read --&gt;|否| Permission{权限足够?}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  Permission --&gt;|否| Deny[拒绝并提示]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  Permission --&gt;|是| Dangerous{危险操作?}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  Dangerous --&gt;|否| Audit[记录审计]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  Dangerous --&gt;|是| Confirm[请求用户确认]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  Confirm --&gt;|取消| Deny</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  Confirm --&gt;|确认| Undo[设置撤销窗口]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  Undo --&gt; Audit</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  Audit --&gt; Execute[执行写入]</span></span></code></pre></div><h2 id="审计日志" tabindex="-1">审计日志 <a class="header-anchor" href="#审计日志" aria-label="Permalink to “审计日志”">​</a></h2><p>审计日志用于回答两个问题：</p><ol><li>AI 或用户刚刚做了什么。</li><li>如果结果不符合预期，应该从哪一步排查。</li></ol><p>日志可在面板中查看和清除。</p><h2 id="oauth-与本地加密保险箱" tabindex="-1">OAuth 与本地加密保险箱 <a class="header-anchor" href="#oauth-与本地加密保险箱" aria-label="Permalink to “OAuth 与本地加密保险箱”">​</a></h2><ul><li>Internal Integration Token、OAuth access token、refresh token、AI API Key、GitHub Token、Obsidian API Key 与 Public OAuth 的 <code>Client Secret</code> 都属于敏感凭证。</li><li>这些敏感凭证现在默认写入本地加密保险箱，而不是继续以旧明文键长期保存在浏览器存储里。</li><li>保险箱需要用户本地设置口令并在当前会话解锁；解锁后敏感凭证只在当前会话内可读，重新锁定后需要再次解锁。</li><li>非敏感配置仍保存在浏览器本地存储中，例如目标数据库 ID、面板位置、来源偏好和 OAuth 的 <code>Client ID</code> / <code>Redirect URI</code>。</li><li>「断开授权」只清除本地 access token / refresh token，不会撤销 Notion 后台已经批准的授权，也不会自动删除你保留的 OAuth 基础配置。</li></ul><h2 id="v3-7-0-安全加固" tabindex="-1">v3.7.0 安全加固 <a class="header-anchor" href="#v3-7-0-安全加固" aria-label="Permalink to “v3.7.0 安全加固”">​</a></h2><p>v3.7.0 对用户脚本权限域和 AI 输入链路做了系统性加固：</p><h3 id="userscript-权限域收窄" tabindex="-1">Userscript 权限域收窄 <a class="header-anchor" href="#userscript-权限域收窄" aria-label="Permalink to “Userscript 权限域收窄”">​</a></h3><ul><li><code>@match</code> 从 <code>*://*/*</code> 替换为 6 个显式站点模式（linux.do、notion.so、github.com、zhihu.com）。</li><li><code>@connect</code> 从 <code>*</code> 替换为 9 个显式域名白名单（api.notion.com、linux.do、s3.amazonaws.com、api.openai.com、api.anthropic.com、generativelanguage.googleapis.com、api.github.com、zhihu.com）。</li><li>新增 <code>@include</code> 正则白名单 + <code>@exclude</code> 排除搜索引擎/邮箱/localhost，提供纵深防御。</li><li>这阻止了用户脚本向任意域名发起网络请求（如攻击者控制的 exfil 端点）。</li></ul><h3 id="ai-prompt-injection-多层防御" tabindex="-1">AI Prompt Injection 多层防御 <a class="header-anchor" href="#ai-prompt-injection-多层防御" aria-label="Permalink to “AI Prompt Injection 多层防御”">​</a></h3><ul><li><strong>XML 标签隔离</strong>：AI 分类 prompt 将用户内容包裹在 <code>&lt;user_content&gt;</code> XML 标签中，与系统指令分离，降低 prompt injection 风险。</li><li><strong>ChatUI 输出净化</strong>：<code>escapeHtml</code> 使用浏览器原生 <code>textContent→innerHTML</code> 转义；<code>safeMarkdown</code> 先转义全部 HTML，再选择性恢复安全 Markdown 格式（粗体、换行），防止注入 HTML/JS 在聊天 UI 中渲染。</li><li><strong>UI 全局 escapeHtml</strong>：所有用户可控文本（数据库名、页面标题、错误消息、书签标题、标签、文件名等）在插入 HTML 前统一经过 <code>Utils.escapeHtml</code> 转义，覆盖 50+ 处拼接点。</li></ul><h3 id="operationguard-setlevel-验证" tabindex="-1">OperationGuard setLevel 验证 <a class="header-anchor" href="#operationguard-setlevel-验证" aria-label="Permalink to “OperationGuard setLevel 验证”">​</a></h3><p><code>setLevel</code> 方法现在强制校验输入值必须为 0-3 的整数，拒绝 <code>NaN</code>、<code>Infinity</code>、负数或超范围值，防止无效权限级别绕过权限系统。</p><h3 id="已知待办" tabindex="-1">已知待办 <a class="header-anchor" href="#已知待办" aria-label="Permalink to “已知待办”">​</a></h3><ul><li><strong>Extension SSRF 白名单严格匹配</strong>：当前 background service worker 的 URL 白名单使用简单字符串匹配，可被 <code>evil.amazonaws.com.attacker.com</code> 绕过。应改用 URL 构造函数解析 hostname 后精确匹配，并限制协议为 https、端口为默认端口。</li><li><strong>Extension CredentialVault 移植</strong>：Chrome Extension 版本中 API key 通过 <code>chrome.storage.local</code> 明文存储，CredentialVault AES-256-GCM 加密机制尚未移植到 Extension 侧。</li></ul><h2 id="v3-7-3-安全加固" tabindex="-1">v3.7.3 安全加固 <a class="header-anchor" href="#v3-7-3-安全加固" aria-label="Permalink to “v3.7.3 安全加固”">​</a></h2><p>v3.7.3 针对 API key 泄露和弱随机数做了专项修复：</p><h3 id="api-key-泄露防护" tabindex="-1">API Key 泄露防护 <a class="header-anchor" href="#api-key-泄露防护" aria-label="Permalink to “API Key 泄露防护”">​</a></h3><ul><li><strong>AI 请求 baseUrl 校验</strong>：<code>AIService._normalizeBaseUrl</code> 内置 <code>UrlValidator.validateAiBaseUrl</code>，仅允许白名单域名（<code>api.openai.com</code>、<code>api.anthropic.com</code>、<code>generativelanguage.googleapis.com</code>）或 HTTPS 非内网域名，阻止攻击者通过自定义 <code>baseUrl</code> 将 <code>Authorization</code> 头重定向到恶意服务器（SEC-001）。</li><li><strong>Obsidian API URL 本地限制</strong>：<code>ObsidianAPI</code> 三个方法入口调用 <code>UrlValidator.validateObsidianUrl</code>，仅允许 <code>127.0.0.1</code>/<code>localhost</code>/<code>::1</code>，阻止篡改存储值后的 API key 泄露（SEC-002）。</li><li><strong>私有网段拦截</strong>：<code>UrlValidator._isPrivateHost</code> 拦截 <code>10.x</code>/<code>172.16-31.x</code>/<code>192.168.x</code>/<code>169.254.x</code> 私有 IP 和 link-local 地址，防止 SSRF。</li></ul><h3 id="弱随机数消除" tabindex="-1">弱随机数消除 <a class="header-anchor" href="#弱随机数消除" aria-label="Permalink to “弱随机数消除”">​</a></h3><ul><li><strong>OAuth state token</strong>：<code>Utils.randomToken</code> 移除 <code>Math.random()</code> 回退，在 <code>crypto.getRandomValues</code> 不可用时抛出错误（SEC-005）。</li><li><strong>审计日志 event ID</strong>：<code>OperationLog.createEventId</code> 从 <code>Math.random()</code> 改为 <code>crypto.getRandomValues</code>（SEC-015）。</li><li><strong>API key hash</strong>：<code>WorkspaceService.buildWorkspaceData</code> 的 <code>apiKeyHash</code> 从直接截取后 8 位改为 djb2 hash，避免部分暴露 API key（SEC-011）。</li></ul><h2 id="v3-7-2-ui-安全加固" tabindex="-1">v3.7.2 UI 安全加固 <a class="header-anchor" href="#v3-7-2-ui-安全加固" aria-label="Permalink to “v3.7.2 UI 安全加固”">​</a></h2><p>v3.7.2 通过 UI Odyssey 全维度审查修复了 UI 层面的安全问题：</p><h3 id="innerhtml-注入防护" tabindex="-1">innerHTML 注入防护 <a class="header-anchor" href="#innerhtml-注入防护" aria-label="Permalink to “innerHTML 注入防护”">​</a></h3><ul><li><code>NotionSiteUI.showStatus</code> 和 <code>UI.showStatus</code> 两处状态显示函数通过 <code>innerHTML</code> 渲染消息内容，此前直接插入 <code>message</code> 和 <code>type</code> 参数，存在 XSS 风险。</li><li>现在两处均使用 <code>Utils.escapeHtml(message)</code> 和 <code>Utils.escapeHtml(type)</code> 对动态内容转义后再插入。</li><li><code>GenericUI.showStatus</code> 使用 <code>textContent</code> 赋值，天然免疫 XSS，无需修改。</li><li>Obsidian 测试连接状态的 <code>innerHTML</code> 中 <code>result.error</code> 和 <code>e.message</code> 也已加 <code>escapeHtml</code>。</li></ul><h3 id="导出操作防重入" tabindex="-1">导出操作防重入 <a class="header-anchor" href="#导出操作防重入" aria-label="Permalink to “导出操作防重入”">​</a></h3><ul><li><code>exportBtn.onclick</code> 和 <code>obsExportBtn.onclick</code> 入口处检查 <code>disabled</code> 状态，操作中设 <code>disabled = true</code>，<code>finally</code> 中恢复 <code>disabled = false</code>，防止并发点击导致重复导出。</li></ul><h3 id="除零与-dom-爆炸防护" tabindex="-1">除零与 DOM 爆炸防护 <a class="header-anchor" href="#除零与-dom-爆炸防护" aria-label="Permalink to “除零与 DOM 爆炸防护”">​</a></h3><ul><li><code>showProgress</code> 中 <code>current / total</code> 除法增加 <code>total &gt; 0</code> 前置检查，避免 <code>total = 0</code> 时产生 <code>NaN</code>。</li><li>导出报告失败项截断为最多 20 条，错误文本截断为 120 字符，防止大量失败项导致 DOM 爆炸。</li></ul><h3 id="状态定时器冲突修复" tabindex="-1">状态定时器冲突修复 <a class="header-anchor" href="#状态定时器冲突修复" aria-label="Permalink to “状态定时器冲突修复”">​</a></h3><ul><li><code>showStatus</code> 连续调用时，旧定时器可能在新消息显示期间触发 <code>container.innerHTML = &quot;&quot;</code>，导致新消息被提前清除。</li><li>现在每次调用前先 <code>clearTimeout(container._statusTimer)</code>，确保只有最新的定时器生效。</li></ul><h2 id="推荐安全实践" tabindex="-1">推荐安全实践 <a class="header-anchor" href="#推荐安全实践" aria-label="Permalink to “推荐安全实践”">​</a></h2><ul><li>日常使用保持「标准」权限。</li><li>危险操作确认保持开启。</li><li>只在需要移动、归档、数据库结构操作时临时切到「高级」。</li><li>首次保存 Notion Token、OAuth Client Secret、AI API Key 等敏感凭证前，先初始化并解锁本地保险箱。</li><li>不要把共享生产级 OAuth Client Secret 放进前端配置。</li><li>在批量操作前先对少量数据试运行。</li></ul>`,40)])])}const k=a(l,[["render",s]]);export{u as __pageData,k as default};
